    display: inline-flex;
    align-items: center;
    gap: 10px;
    padding: 12px 20px;
    background: #1a3c1a;
    color: #fafffa;
    border: none;
    border-radius: 8px;
    font-size: 1.1rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.2s, color 0.2s;
}
.history-modal-trigger:hover {
    background: #2a5a2a;
    color: #eac31b;
}
.history-modal-trigger-icon { font-size: 1.2em; }
.history-modal-trigger-title { font-family: inherit; }

.history-modal-overlay {
    position: fixed;
    inset: 0;
    z-index: 1000;
    background: rgba(0,0,0,0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 20px;
    opacity: 0;
    visibility: hidden;
    transition: opacity 0.3s, visibility 0.3s;
}
.history-modal-overlay[hidden] { display: none; }
.history-modal-overlay.history-modal-open {
    opacity: 1;
    visibility: visible;
    display: flex;
}
.history-modal-overlay.history-modal-open[hidden] { display: none; }

.history-modal {
    background: #fff;
    max-width: 640px;
    max-height: 90vh;
    border-radius: 8px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.3);
    overflow: hidden;
    display: flex;
    flex-direction: column;
    outline: none;
}
.history-modal-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 20px 24px;
    border-bottom: 2px solid #1a3c1a;
    background: #fafffa;
}
.history-modal-header h2 { color: #1a3c1a; margin: 0; font-size: 1.35rem; }
.history-modal-close {
    width: 36px;
    height: 36px;
    border: none;
    background: transparent;
    color: #1a3c1a;
    font-size: 28px;
    line-height: 1;
    cursor: pointer;
    border-radius: 4px;
    padding: 0;
    display: flex;
    align-items: center;
    justify-content: center;
}
.history-modal-close:hover { background: rgba(26,60,26,0.1); color: #eac31b; }
.history-modal-body {
    padding: 24px;
    overflow-y: auto;
    flex: 1;
    font-size: 1.2rem;
    line-height: 1.7;
    color: #333;
}
.history-modal-body p { margin-bottom: 1em; }
.history-modal-body h3 { color: #1a3c1a; margin: 1.5em 0 0.5em; font-size: 1.15rem; }
.history-modal-body h3:first-child { margin-top: 0; }
</style>
